SELECT id, name, code, status, quota_config, description, created_at, updated_at
FROM tenant
WHERE id = #{id}

SELECT id, name, code, status, quota_config, description, created_at, updated_at
FROM tenant
WHERE code = #{code}

SELECT id, name, code, status, quota_config, description, created_at, updated_at FROM tenant WHERE 1=1
AND name LIKE '%' || #{name} || '%'
AND status = #{status}
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM tenant WHERE 1=1
AND name LIKE '%' || #{name} || '%'
AND status = #{status}
